import React, { useState } from 'react';
import Header from './Header';

const SimplePage = () => {
  const [count, setCount] = useState(0);
  const [usuario, setUsuario] = useState(null);

  const handleLogout = () => {
    setUsuario(null);
  };

  const handleClick = () => {
    setCount(count + 1);
  };

  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f5f5f5', minHeight: '100vh' }}>
      <Header usuario={usuario} onLogout={handleLogout} />
      <div style={{ padding: '40px', textAlign: 'center' }}>
      <h1>Contador de TEUs</h1>
      <p>Botón presionado {count} veces</p>
      <button
        onClick={handleClick}
        style={{
          padding: '10px 20px',
          fontSize: '16px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: 'pointer'
        }}
      >
        Presionar Botón
      </button>
      <a
          href="/landing"
          style={{
            display: 'block',
            textAlign: 'center',
            color: '#007bff',
            textDecoration: 'none',
            fontSize: '14px'
          }}
        >
          Volver a la página principal
        </a>
      </div>
    </div>
  );
};

export default SimplePage;
